+    );
+
+    let node_compat = inv
+        .evidence
+        .iter()
+        .find(|ev| {
+            ev.specimen_id == "scoped_package_type_module_extensionless_relative_node_compat"
+        })
+        .unwrap();
+    assert_eq!(
+        node_compat.compatibility_mode,
+        CompatibilityMode::NodeCompat
+    );
+    assert_eq!(
+        node_compat.actual_outcome,
+        InteropActualOutcome::LinkFailure
+    );
