+        node_compat
+            .error_detail
+            .as_deref()
+            .is_some_and(|detail| detail.contains("unable to resolve relative specifier './sub'"))
+    );
+
+    let bun_compat = inv
+        .evidence
+        .iter()
+        .find(|ev| ev.specimen_id == "scoped_package_type_module_extensionless_relative_bun_compat")
